SELECT pc.id, pc.last_name AS name, pc.employee_number AS employee_id, pc.job_family, pc.job_category, pc.job_subcategory, pc.firstdept AS department_level1, pc.seconddept AS department_level2, pc.thirddept AS department_level3, pc.fourthdept AS department_level4, pc.fifthdept AS department_level5, pc.sixthdept AS department_level6, SUBSTRING_INDEX(pc.lowest_dept, '/', 1) AS min_department, NULL AS is_cadre, NULL AS cadre_type, NULL AS is_expert, NULL AS is_frontline_manager, NULL AS organization_maturity, NULL AS position_maturity, pc.current_credit AS current_credits, pc.personal_credit_completion_rate AS completion_rate, pc.dept_benchmark_completion_rate AS benchmark_rate, DATE_FORMAT(pc.credit_completion_date, '%Y-%m-%d') AS completion_date, ROUND( DATEDIFF(CURDATE(), DATE(CONCAT(YEAR(CURDATE()), '-01-01'))) / DATEDIFF(DATE(CONCAT(YEAR(CURDATE()), '-12-31')), DATE(CONCAT(YEAR(CURDATE()), '-01-01'))) * pc.target_credit, 1 ) AS schedule_target, CASE WHEN pc.personal_credit_completion_rate >= 100 THEN '正常' WHEN pc.personal_credit_completion_rate >= 80 THEN '轻度预警' ELSE '滞后预警' END AS status, CASE WHEN pc.personal_credit_completion_rate >= 100 THEN 'success' WHEN pc.personal_credit_completion_rate >= 80 THEN 'warning' ELSE 'danger' END AS status_type FROM t_personal_credit pc WHERE 1=1
AND pc.firstdeptcode = #{request.deptCode}
AND pc.seconddeptcode = #{request.deptCode}
AND pc.thirddeptcode = #{request.deptCode}
AND pc.fourthdeptcode = #{request.deptCode}
AND pc.fifthdeptcode = #{request.deptCode}
AND pc.sixthdeptcode = #{request.deptCode}
AND (pc.firstdeptcode = #{request.deptCode} OR pc.seconddeptcode = #{request.deptCode} OR pc.thirddeptcode = #{request.deptCode} OR pc.fourthdeptcode = #{request.deptCode} OR pc.fifthdeptcode = #{request.deptCode} OR pc.sixthdeptcode = #{request.deptCode} OR pc.lowest_dept_number = #{request.deptCode})
AND pc.job_family = #{request.jobFamily}
AND pc.job_category = #{request.jobCategory}
AND pc.job_subcategory = #{request.jobSubCategory}
ORDER BY pc.employee_number LIMIT #{request.pageSize} OFFSET #{offset}

